const body = $json.body ?? {};

const message = body.message ?? body.user_message ?? '';
const sessionId = body.sessionId ?? null;
const state = body.state ?? {
  phase: 'qualification',
  lead_score: 0,
};

const reply = message
  ? `Echo (session: ${sessionId ?? 'n/a'}): ${message}`
  : 'No message received. Send JSON: {"message":"...","sessionId":"..."}';

return [{
  json: {
    reply,
    state,
  },
}];
